import {
  tailwindPlugin,
  tailwindConfigBase,
  httpClientGenPlugin,
  type BuildHttpClientConfig,
  type TailwindPluginOptions,
} from "@hushkey/howl/plugins";

import { HowlBuilder } from "@hushkey/howl/dev";
import { tailwindPlugin } from "@hushkey/howl/plugins";
import { app } from "./server/main.ts";

const builder = new HowlBuilder(app, {
  root: import.meta.dirname,
  importApp: () => app,
  serverEntry: "./server/main.ts",
  clientEntry: "./client/pages/_app.ts",
});

tailwindPlugin(builder.getBuilder("default")!, {
  // Optional: skip vendor or legacy CSS
  exclude: ["/vendor/**", /\.legacy\.css$/],
});

if (Deno.args.includes("build")) await builder.build();
else await builder.listen();

// tailwind.config.ts
import { tailwindConfigBase } from "@hushkey/howl/plugins";
import daisyui from "daisyui";
import type { Config } from "tailwindcss";

export default {
  ...tailwindConfigBase,
  content: [
    ...tailwindConfigBase.content!,
    "./client/components/**/*.{ts,tsx}",
  ],
  theme: {
    extend: {
      ...tailwindConfigBase.theme?.extend,
      colors: { brand: "#5B6CFF" },
    },
  },
  plugins: [daisyui],
} satisfies Config;

@import "tailwindcss";

/* Optional: daisyUI v5 themes, custom layers, etc. */
@plugin "daisyui" {
  themes: light --default, dark --prefersdark;
}

@layer base {
  html { font-family: ui-sans-serif, system-ui, sans-serif; }
}

import { HowlBuilder } from "@hushkey/howl/dev";
import { httpClientGenPlugin, tailwindPlugin } from "@hushkey/howl/plugins";
import { app } from "./server/main.ts";

const builder = new HowlBuilder(app, {
  root: import.meta.dirname,
  importApp: () => app,
  serverEntry: "./server/main.ts",
  plugins: [
    httpClientGenPlugin({
      apiDir: "./server/apis",
      outputFile: "./packages/http-client/mod.ts",
      // Optional cross-package schema resolution:
      aliases: { "@packages/": "../../packages/" },
    }),
  ],
});

tailwindPlugin(builder.getBuilder("default")!);

interface BuildHttpClientConfig {
  /** Directory containing *.api.ts files. Absolute or relative to cwd. */
  apiDir: string;
  /** Output path for the generated client. Defaults to packages/http-client/mod.ts. */
  outputFile?: string;
  /** Import alias map, resolved relative to cwd, for cross-package schema refs. */
  aliases?: Record<string, string>;
}

import { http } from "./packages/http-client/mod.ts";

// GET /api/public/ping
const pong = await http.api.public.ping.$get();

// POST /api/users/[id]/avatar with typed params + body
await http.api.users[":id"].avatar.$post({
  params: { id: "u_123" },
  body: { url: "https://..." },
  origin: "server",
});
